# Concrete implementations of shapes
from shapes import Color, IShape, IColored

struct Point2D:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def distance_to(self, other: Point2D) -> float:
        dx: float = self.x - other.x
        dy: float = self.y - other.y
        return pow(dx * dx + dy * dy, 0.5)

@abstract
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @abstract
    def describe(self) -> str: ...

class Circle(Shape, IShape, IColored):
    center: Point2D
    radius: float
    _color: Color

    def __init__(self, name: str, center: Point2D, radius: float, color: Color):
        super().__init__(name)
        self.center = center
        self.radius = radius
        self._color = color

    @override
    def describe(self) -> str:
        return "Circle: " + self.name

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def get_color(self) -> Color:
        return self._color

class Rectangle(Shape, IShape, IColored):
    top_left: Point2D
    width: float
    height: float
    _color: Color

    def __init__(self, name: str, top_left: Point2D, width: float, height: float, color: Color):
        super().__init__(name)
        self.top_left = top_left
        self.width = width
        self.height = height
        self._color = color

    @override
    def describe(self) -> str:
        return "Rectangle: " + self.name

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def get_color(self) -> Color:
        return self._color

