# Utility functions for shape operations
from shapes import Color
from geometry import Point2D, Shape, Circle, Rectangle

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total += s.area()
    return total

def color_name(c: Color) -> str:
    if c == Color.RED:
        return "red"
    elif c == Color.GREEN:
        return "green"
    else:
        return "blue"

def midpoint(a: Point2D, b: Point2D) -> Point2D:
    mid_x: float = (a.x + b.x) / 2.0
    mid_y: float = (a.y + b.y) / 2.0
    return Point2D(mid_x, mid_y)
